// 获取入参
const items = $input.all();

// 遍历每一个 item 并更新 joborder_type
items.forEach(item => {
  if (item.json.joborder_type === "包装") {
    item.json.joborder_type = "PACK";
  } else if (item.json.joborder_type === "组装") {
    item.json.joborder_type = "ASSY";
  } else if (item.json.joborder_type === "售后") {
    item.json.joborder_type = "AfterSale";
  }
});

// 返回更新后的 items
return items;

let res = [];
for (const item of $input.all()) {
  const itemContent = item.json;
  if (!itemContent) continue; // 如果 itemContent 为空则跳过

  // 遍历 itemContent 的所有项
  for (const key in itemContent) {
    if (!itemContent.hasOwnProperty(key)) continue;

    const cur = itemContent[key];

    if (key === 'errPrintinfo' && Array.isArray(cur) && cur.length > 0) {
      const temp = cur
        .map(errPrintinfo => ({
          name: errPrintinfo['打印模板'],
          Reason: '该打印模板不存在',
        }))
        .filter(item => item.name); // 过滤掉 name 为空的对象
      res = res.concat(temp);
    } else if (key === 'success' && Array.isArray(cur) && cur.length > 0) {
      const temp = cur
        .map(success => ({
          name: success['joborder_number'],
          Reason: '该工单已成功创建',
        }))
        .filter(item => item.name); // 过滤掉 name 为空的对象
      res = res.concat(temp);
    } else if (key === 'errProcess' && Array.isArray(cur) && cur.length > 0) {
      const temp = cur
        .map(errProcess => ({
          name: errProcess['工艺流程'],
          Reason: '该工艺流程不存在',
        }))
        .filter(item => item.name); // 过滤掉 name 为空的对象
      res = res.concat(temp);
    } else if (key === 'errProductcode' && Array.isArray(cur) && cur.length > 0) {
        const temp = cur
        .map(errProductcode => ({
          name: errProductcode['产品物料号'],
          Reason: '该物料号不存在',
        }))
        .filter(item => item.name); // 过滤掉 name 为空的对象
      res = res.concat(temp);
       } else if (key === 'errJoborder' && Array.isArray(cur) && cur.length > 0) {
        const temp = cur
        .map(errJoborder => ({
          name: errJoborder['joborder_number'],
          Reason: '该工单号重复',
        }))
        .filter(item => item.name); // 过滤掉 name 为空的对象
      res = res.concat(temp);
    }
  }
}

// 只有在 res 为空时添加 '上传失败'
if (res.length === 0) {
  res.push({ SN: null, Reason: '上传失败' });
}

return {
  result: res
};

const uniqueData = [];
const seen = new Set();

for (const item of items) {
    // 根据printinfo_id 和 工单号来判断重复
    const key = `${item.json.printinfo_id}-${item.json.工单号}`;
    if (!seen.has(key)) {
        seen.add(key);
        uniqueData.push(item);
    }
}

return uniqueData;

